/*!50001 VIEW `agency_incidents_2024` AS select `a`.`agency_name` AS `agency_name`,count(`ia`.`incident_id`) AS `incident_count` from ((`incidentagency` `ia` join `agency` `a` on((`ia`.`agency_id` = `a`.`agency_id`))) join `incident` `i` on((`ia`.`incident_id` = `i`.`incident_id`))) where (year(`i`.`incident_date`) = 2024) group by `a`.`agency_name` order by `incident_count` desc */;
