/*!50001 CREATE ALGORITHM=UNDEFINED */
/*!50013 DEFINER=`root`@`localhost` SQL SECURITY DEFINER */
/*!50001 VIEW `incident_officer_races_2024` AS select `o`.`race` AS `race`,count(`io`.`officer_id`) AS `officer_incidents`,concat(round(((count(`io`.`officer_id`) * 100.0) / (select count(`io2`.`officer_id`) from (`incidentofficer` `io2` join `incident` `i2` on((`io2`.`incident_id` = `i2`.`incident_id`))) where (year(`i2`.`incident_date`) = 2024))),2),'%') AS `percentage` from ((`incidentofficer` `io` join `officer` `o` on((`io`.`officer_id` = `o`.`officer_id`))) join `incident` `i` on((`io`.`incident_id` = `i`.`incident_id`))) where (year(`i`.`incident_date`) = 2024) group by `o`.`race` order by `officer_incidents` desc */;
/*!50001 SET character_set_client      = @saved_cs_client */;
